100→        </g>
101→      );
102→    }
103→    case 'table': {
104→      const inset = width * 0.06;
105→      const legInset = width * 0.1;
106→      const legDInset = depth * 0.1;
107→      const legR = width * 0.035;
108→      return (
109→        <g transform={transform}>
110→          {/* Inner highlight rect (bevel) */}
