144→          <line x1={0} y1={hd} x2={0} y2={hd + depth * 0.3}
145→            {...PRIMARY} {...NSS} fill="none" />
146→          {/* Base bar */}
147→          <line x1={-width * 0.18} y1={hd + depth * 0.3} x2={width * 0.18} y2={hd + depth * 0.3}
148→            {...PRIMARY} {...NSS} fill="none" />
149→        </g>
150→      );
151→    }
152→    case 'sofa': {
153→      const pad = width * 0.04;
154→      const backH = depth * 0.22;
155→      const armW = width * 0.08;
156→      const seatTop = -hd + backH + pad;
157→      const seatBot = hd - pad;
158→      const seatLeft = -hw + armW + pad;
159→      const seatRight = hw - armW - pad;
160→      const seatW = seatRight - seatLeft;
161→      const cushionW = seatW / 3;
162→      return (
163→        <g transform={transform}>
164→          {/* Backrest */}
165→          <rect x={-hw + pad} y={-hd + pad} width={width - pad * 2} height={backH}
166→            rx={width * 0.02} fill="none" {...PRIMARY} {...NSS} />
167→          {/* Left armrest */}
168→          <rect x={-hw + pad} y={-hd + backH} width={armW} height={depth - backH - pad}
169→            rx={width * 0.015} fill="none" {...PRIMARY} {...NSS} />
170→          {/* Right armrest */}
171→          <rect x={hw - armW - pad} y={-hd + backH} width={armW} height={depth - backH - pad}
172→            rx={width * 0.015} fill="none" {...PRIMARY} {...NSS} />
173→          {/* 3 seat cushion rects */}
174→          {[0, 1, 2].map(i => (
175→            <rect key={i}
176→              x={seatLeft + i * cushionW + pad * 0.3}
177→              y={seatTop + pad * 0.3}
178→              width={cushionW - pad * 0.6}
179→              height={seatBot - seatTop - pad * 0.6}
180→              rx={width * 0.01}
181→              fill="none" {...SECONDARY} {...NSS}
182→            />
183→          ))}
184→          {/* Cushion seam dash lines */}
185→          {[1, 2].map(i => (
186→            <line key={i}
187→              x1={seatLeft + i * cushionW} y1={seatTop + pad}
188→              x2={seatLeft + i * cushionW} y2={seatBot - pad}
189→              {...SECONDARY} {...NSS} fill="none"
190→              strokeDasharray="8 6"
191→            />
192→          ))}
193→        </g>
194→      );
195→    }
196→    case 'bed': {
197→      const headH = depth * 0.08;
198→      const pillowW = width * 0.38;
199→      const pillowH = depth * 0.12;
200→      const pillowGap = width * 0.04;
201→      const pillowY = -hd + headH + depth * 0.04;
202→      return (
203→        <g transform={transform}>
204→          {/* Headboard */}
205→          <rect x={-hw + width * 0.02} y={-hd + depth * 0.01} width={width * 0.96} height={headH}
206→            rx={width * 0.02} fill="none" {...PRIMARY} {...NSS} />
207→          {/* Left pillow */}
208→          <rect x={-pillowGap / 2 - pillowW} y={pillowY} width={pillowW} height={pillowH}
209→            rx={width * 0.04} fill="none" {...PRIMARY} {...NSS} />
210→          {/* Right pillow */}
211→          <rect x={pillowGap / 2} y={pillowY} width={pillowW} height={pillowH}
212→            rx={width * 0.04} fill="none" {...PRIMARY} {...NSS} />
213→          {/* Blanket fold line */}
214→          <line x1={-hw + width * 0.08} y1={hd - depth * 0.35}
215→            x2={hw - width * 0.08} y2={hd - depth * 0.35}
216→            {...SECONDARY} {...NSS} fill="none" />
217→          {/* Inner highlight */}
218→          <rect x={-hw + width * 0.05} y={-hd + headH + depth * 0.02}
219→            width={width * 0.90} height={depth - headH - depth * 0.04}
220→            rx={width * 0.02} fill="none" {...HIGHLIGHT} {...NSS} />
221→        </g>
222→      );
223→    }
224→    default:
225→      return null;
226→  }
227→}
