586→const initialProject = createProject();
587→
588→const initialState = {
589→  project: initialProject,
590→  isDirty: false,
591→  lastSavedAt: null,
592→  savedSnapshot: snapshotProject(initialProject),
593→  history: [],
594→  future: [],
595→};
596→
597→export function ProjectProvider({ children }) {
598→  const [state, dispatch] = useReducer(projectReducer, initialState);
599→  return (
600→    <ProjectContext.Provider value={{ state, dispatch }}>
601→      {children}
602→    </ProjectContext.Provider>
603→  );
604→}
605→
606→export function useProject() {
607→  const ctx = useContext(ProjectContext);
608→  if (!ctx) throw new Error('useProject must be used within ProjectProvider');
609→  const { state, dispatch } = ctx;
610→
611→  const duplicateFloor = (floorId) => {
612→    const floor = state.project.floors.find((entry) => entry.id === floorId) || null;
613→    return floor ? createDuplicatedFloor(floor) : null;
614→  };
615→
616→  return {
617→    project: state.project,
618→    isDirty: state.isDirty,
619→    lastSavedAt: state.lastSavedAt,
620→    canUndo: state.history.length > 0,
621→    canRedo: state.future.length > 0,
622→    dispatch,
623→    duplicateFloor,
624→    getFloor: (floorId) => state.project.floors.find(f => f.id === floorId),
625→  };
626→}
