 50→export default function SvgCanvas() {
 51→  const svgRef = useRef(null);
 52→  const isPanning = useRef(false);
 53→  const lastPanPos = useRef({ x: 0, y: 0 });
 54→  const spaceHeld = useRef(false);
 55→  const cursorPosRef = useRef({ x: 0, y: 0 });
 56→  const [cursorPos, setCursorPos] = useState({ x: 0, y: 0 });
 57→
 58→  const { project, dispatch, getFloor } = useProject();
 59→  const editor = useEditor();
 60→  const {
 61→    activeTool, selectedId, selectedType, toolState,
 62→    viewport, showGrid, snapEnabled, activeFloorId, statusMessage, viewMode, activeSectionCutId,
 63→    regionSelection, pastePreview, maximizedPanel,
 64→    dispatch: editorDispatch,
 65→  } = editor;
 66→
 67→  const floor = getFloor(activeFloorId);
 68→  const {
 69→    copySelection,
 70→    cutSelection,
 71→    beginPaste,
 72→    updatePastePreview,
 73→    cancelPaste,
 74→    placePaste,
 75→    previewContent,
 76→  } = usePlanClipboardController();
 77→
 78→  const tool = useEditorTool({
 79→    activeTool,
 80→    dispatch,
 81→    editorDispatch,
 82→    project,
 83→    getFloor,
 84→    activeFloorId,
 85→    viewport,
 86→    snapEnabled,
 87→    selectedId,
 88→    selectedType,
 89→    toolState,
 90→    viewMode,
 91→  });
 92→
 93→  const getModelPos = useCallback((e) => {
 94→    const rect = svgRef.current.getBoundingClientRect();
 95→    return screenToModel(e.clientX, e.clientY, viewport, rect);
 96→  }, [viewport]);
 97→
 98→  const handleMouseDown = useCallback((e) => {
 99→    // Middle mouse or space+left for pan
100→    if (e.button === 1 || (e.button === 0 && spaceHeld.current)) {
101→      isPanning.current = true;
102→      lastPanPos.current = { x: e.clientX, y: e.clientY };
103→      e.preventDefault();
104→      return;
105→    }
106→
107→    const modelPos = getModelPos(e);
108→    if (pastePreview?.active && e.button === 0) {
109→      placePaste(modelPos);
110→      return;
111→    }
112→    tool.onMouseDown(modelPos, e);
113→  }, [getModelPos, pastePreview, placePaste, tool]);
114→
115→  const handleMouseMove = useCallback((e) => {
116→    if (isPanning.current) {
117→      const dx = e.clientX - lastPanPos.current.x;
118→      const dy = e.clientY - lastPanPos.current.y;
119→      editorDispatch({ type: 'PAN', dx, dy });
120→      lastPanPos.current = { x: e.clientX, y: e.clientY };
121→      return;
122→    }
123→
124→    const modelPos = getModelPos(e);
125→    cursorPosRef.current = modelPos;
126→    setCursorPos(modelPos);
127→    if (pastePreview?.active) {
128→      updatePastePreview(modelPos);
129→      return;
130→    }
131→    tool.onMouseMove(modelPos, e);
132→  }, [getModelPos, pastePreview, tool, updatePastePreview, editorDispatch]);
133→
134→  const handleMouseUp = useCallback((e) => {
135→    if (isPanning.current) {
136→      isPanning.current = false;
137→      return;
138→    }
139→    if (pastePreview?.active) return;
140→    const modelPos = getModelPos(e);
141→    tool.onMouseUp(modelPos, e);
142→  }, [getModelPos, pastePreview, tool]);
143→
144→  const handleDoubleClick = useCallback((e) => {
145→    if (pastePreview?.active) return;
146→    const modelPos = getModelPos(e);
147→    tool.onDoubleClick(modelPos, e);
148→  }, [getModelPos, pastePreview, tool]);
149→
150→  const handleWheel = useCallback((e) => {
151→    e.preventDefault();
152→    const rect = svgRef.current.getBoundingClientRect();
153→    const mouseX = e.clientX - rect.left;
154→    const mouseY = e.clientY - rect.top;
155→
156→    const direction = e.deltaY < 0 ? 1 : -1;
157→    const factor = direction > 0 ? ZOOM_FACTOR : 1 / ZOOM_FACTOR;
158→    const newZoom = Math.max(MIN_ZOOM, Math.min(MAX_ZOOM, viewport.zoom * factor));
159→
160→    // Zoom centered on cursor
161→    const newPanX = mouseX - (mouseX - viewport.panX) * (newZoom / viewport.zoom);
162→    const newPanY = mouseY - (mouseY - viewport.panY) * (newZoom / viewport.zoom);
163→
164→    editorDispatch({ type: 'ZOOM', zoom: newZoom, panX: newPanX, panY: newPanY });
165→  }, [viewport, editorDispatch]);
166→
167→  useEffect(() => {
168→    if (!statusMessage) return undefined;
169→
170→    const timer = window.setTimeout(() => {
171→      editorDispatch({ type: 'CLEAR_STATUS_MESSAGE' });
172→    }, 2500);
173→
174→    return () => window.clearTimeout(timer);
175→  }, [statusMessage, editorDispatch]);
176→
177→  useEffect(() => {
178→    const handleKeyDown = (e) => {
179→      if (isTypingTarget(e.target)) return;
180→
181→      if (e.key === ' ') {
182→        spaceHeld.current = true;
183→        e.preventDefault();
184→      }
185→
186→      if ((e.ctrlKey || e.metaKey) && viewMode === 'plan') {
187→        const key = e.key.toLowerCase();
188→        if (key === 'c') {
189→          e.preventDefault();
190→          copySelection();
191→          return;
192→        }
193→        if (key === 'x') {
194→          e.preventDefault();
195→          cutSelection();
196→          return;
197→        }
198→        if (key === 'v') {
199→          e.preventDefault();
200→          beginPaste(cursorPosRef.current);
201→          return;
202→        }
203→      }
204→
205→      if (e.key === 'Escape' && pastePreview?.active) {
206→        e.preventDefault();
207→        cancelPaste();
208→        return;
209→      }
210→
211→      // Tool shortcuts
212→      if (viewMode === 'plan' && !e.ctrlKey && !e.metaKey) {
213→        switch (e.key.toLowerCase()) {
214→          case 'v':
215→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.SELECT });
216→            return;
217→          case 'm':
218→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.DIMENSION });
219→            return;
220→          case 'w':
221→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.WALL });
222→            return;
223→          case 'b':
224→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.BEAM });
225→            return;
226→          case 't':
227→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.STAIR });
228→            return;
229→          case 'q':
230→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.SECTION });
231→            return;
232→          case 's':
233→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.SLAB });
234→            return;
235→          case 'r':
236→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.ROOM });
237→            return;
238→          case 'd':
239→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.DOOR });
240→            return;
241→          case 'n':
242→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.WINDOW });
243→            return;
244→          case 'c':
245→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.COLUMN });
246→            return;
247→          case 'l':
248→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.LANDING });
249→            return;
250→          case 'f':
251→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.FIXTURE });
252→            editorDispatch({ type: 'UPDATE_TOOL_STATE', payload: { fixtureType: 'kitchenTop', previewRotation: 0 } });
253→            return;
254→        }
255→      }
256→
257→      tool.onKeyDown(e);
258→    };
259→
260→    const handleKeyUp = (e) => {
261→      if (isTypingTarget(e.target)) return;
262→
263→      if (e.key === ' ') {
264→        spaceHeld.current = false;
265→      }
266→    };
267→
268→    window.addEventListener('keydown', handleKeyDown);
269→    window.addEventListener('keyup', handleKeyUp);
270→    return () => {
271→      window.removeEventListener('keydown', handleKeyDown);
272→      window.removeEventListener('keyup', handleKeyUp);
273→    };
274→  }, [beginPaste, cancelPaste, copySelection, cutSelection, pastePreview?.active, tool, editorDispatch, viewMode]);
275→
276→  // Prevent default context menu on SVG
277→  useEffect(() => {
278→    const svg = svgRef.current;
279→    if (!svg) return;
280→    const prevent = (e) => e.preventDefault();
281→    svg.addEventListener('contextmenu', prevent);
282→    svg.addEventListener('wheel', handleWheel, { passive: false });
283→    return () => {
284→      svg.removeEventListener('contextmenu', prevent);
285→      svg.removeEventListener('wheel', handleWheel);
286→    };
287→  }, [handleWheel]);
288→
289→  const cursor = spaceHeld.current ? 'grab' : pastePreview?.active ? 'copy' : tool.getCursor();
290→  const zoomPercent = Math.round(viewport.zoom * 1000);
291→  const displayedTool = viewMode.startsWith('elevation_') ? 'select' : activeTool;
292→  const isCanvasMaximized = maximizedPanel === 'canvas';
293→  const marqueeBounds = toolState.dragType === 'marquee' && toolState.startPos && toolState.currentPos
294→    ? normalizeRectBounds(toolState.startPos, toolState.currentPos)
295→    : null;
296→  const selectionCount = regionSelection?.objectCount || 0;
297→
298→  return (
299→    <div className={styles.canvasContainer}>
300→      <svg
301→        ref={svgRef}
302→        className={styles.svg}
303→        style={{ cursor }}
304→        onMouseDown={handleMouseDown}
305→        onMouseMove={handleMouseMove}
306→        onMouseUp={handleMouseUp}
307→        onDoubleClick={handleDoubleClick}
308→      >
309→        <g transform={`translate(${viewport.panX}, ${viewport.panY}) scale(${viewport.zoom})`}>
310→          {viewMode === 'plan' && showGrid && <GridRenderer />}
311→          {viewMode === 'plan' && showGrid && (
312→            <rect
313→              x={-100000} y={-100000}
314→              width={200000} height={200000}
315→              fill="url(#grid-major)"
316→              style={{ pointerEvents: 'none' }}
317→            />
318→          )}
319→          {floor && (
320→            viewMode === 'plan' ? (
321→              <>
322→                <FixtureDefs />
323→                {(floor.slabs || []).map(slab => (
324→                  <SlabRenderer key={slab.id} slab={slab} selectedId={selectedId} />
325→                ))}
326→                <RoomRenderer rooms={floor.rooms} selectedId={selectedId} />
327→                <RoomPreview toolState={toolState} activeTool={activeTool} />
328→                <WallRenderer walls={floor.walls} columns={floor.columns || []} />
329→                <BeamRenderer beams={floor.beams || []} columns={floor.columns || []} />
330→                <StairRenderer stairs={floor.stairs || []} />
331→                <LandingRenderer landings={floor.landings || []} />
332→                <ColumnRenderer columns={floor.columns || []} />
333→                <FixtureRenderer fixtures={floor.fixtures || []} />
334→                <DoorRenderer doors={floor.doors} walls={floor.walls} />
335→                <WindowRenderer windows={floor.windows} walls={floor.walls} />
336→                {(floor.sectionCuts || []).map(sc => (
337→                  <SectionCutRenderer key={sc.id} sectionCut={sc} selectedId={selectedId} />
338→                ))}
339→                <AnnotationRenderer floor={floor} />
340→                <ClipboardPreviewLayer content={previewContent} />
341→                <RegionSelectionOverlay
342→                  marqueeBounds={marqueeBounds}
343→                  selectionBounds={regionSelection?.bounds || null}
344→                />
345→                <SelectionOverlay
346→                  selectedId={selectedId}
347→                  selectedType={selectedType}
348→                  floor={floor}
349→                  zoom={viewport.zoom}
350→                />
351→                <DimensionPreview toolState={toolState} activeTool={activeTool} />
352→                <WallPreview toolState={toolState} activeTool={activeTool} />
353→                <SlabPreview toolState={toolState} activeTool={activeTool} />
354→                <BeamPreview
355→                  toolState={toolState}
356→                  activeTool={activeTool}
357→                  columns={floor.columns || []}
358→                  floorLevel={getFloorElevation(floor)}
359→                />
360→                <StairPreview
361→                  toolState={toolState}
362→                  activeTool={activeTool}
363→                  floorId={floor.id}
364→                />
365→                <DoorWindowPreview
366→                  toolState={toolState}
367→                  activeTool={activeTool}
368→                  walls={floor.walls}
369→                />
370→                <SectionCutPreview toolState={toolState} activeTool={activeTool} />
371→                <ColumnPreview toolState={toolState} activeTool={activeTool} />
372→                <LandingPreview toolState={toolState} activeTool={activeTool} />
373→                <FixturePreview toolState={toolState} activeTool={activeTool} />
374→              </>
375→            ) : viewMode === 'section_view' ? (
376→              <SectionRenderer
377→                project={project}
378→                floor={floor}
379→                activeSectionCutId={activeSectionCutId}
380→              />
381→            ) : (
382→              <ElevationRenderer
383→                project={project}
384→                floor={floor}
385→                viewMode={viewMode}
386→                selectedId={selectedId}
387→                selectedType={selectedType}
388→              />
389→            )
390→          )}
391→        </g>
392→      </svg>
393→      <button
394→        className={styles.expandBtn}
395→        onClick={() => editorDispatch({ type: 'TOGGLE_MAXIMIZE_PANEL', panel: 'canvas' })}
396→        title={isCanvasMaximized ? 'Restore split view' : 'Maximize canvas'}
397→        aria-label={isCanvasMaximized ? 'Restore split view' : 'Maximize canvas'}
398→      >
399→        {isCanvasMaximized ? <CollapseIcon /> : <ExpandIcon />}
400→      </button>
401→      <div className={styles.statusBar}>
402→        <span>X: {Math.round(cursorPos.x)} mm</span>
403→        <span>Y: {Math.round(cursorPos.y)} mm</span>
404→        <span>Zoom: {zoomPercent}%</span>
405→        <span>View: {viewMode}</span>
406→        <span>Tool: {displayedTool}</span>
407→        {selectionCount > 0 && <span>Selection: {selectionCount} objects</span>}
408→        {pastePreview?.active && <span>Paste: click to place</span>}
409→        {statusMessage && <span className={styles.statusMessage}>{statusMessage}</span>}
410→      </div>
411→    </div>
412→  );
413→}
