157→export default function SheetViewportContent({ source }) {
158→  if (!source || source.kind === 'empty') return null;
159→
160→  if (source.kind === 'plan') {
161→    return <PlanViewportContent floor={source.floor} />;
162→  }
163→
164→  if (source.kind === '3d_preview') {
165→    return <ThreePreviewViewportContent source={source} />;
166→  }
167→
168→  if (source.kind === 'section') {
169→    return <SectionSceneLayer scene={source.scene} showTitle={false} />;
170→  }
171→
172→  if (source.kind === 'elevation') {
173→    return (
174→      <ElevationSceneLayer
175→        scene={source.scene}
176→        annotationScene={source.annotationScene}
177→        showTitle={false}
178→      />
179→    );
180→  }
181→
182→  return null;
183→}
