 75→        fill={SHEET_COLORS.sheetBackdrop}
 76→        stroke="none"
 77→      />
 78→      <rect
 79→        x={scene.border.x}
 80→        y={scene.border.y}
 81→        width={scene.border.width}
 82→        height={scene.border.height}
 83→        fill={SHEET_COLORS.paper}
 84→        stroke={selectedType === 'sheet' && selectedId === sheet.id ? '#0f8f74' : SHEET_COLORS.border}
 85→        strokeWidth={selectedType === 'sheet' && selectedId === sheet.id ? 1 : 0.6}
 86→      />
 87→      <rect
 88→        x={scene.liveArea.x}
 89→        y={scene.liveArea.y}
 90→        width={scene.liveArea.width}
 91→        height={scene.liveArea.height}
 92→        fill="none"
