101→          <g
102→            key={viewport.id}
103→            className="sheet-viewport"
104→            transform={viewport.rotation ? `rotate(${viewport.rotation}, ${viewport.x + viewport.width / 2}, ${viewport.y + viewport.height / 2})` : undefined}
105→          >
106→            <ViewportCaption viewport={viewport} />
107→            <rect
108→              x={viewport.x}
109→              y={viewport.y}
110→              width={viewport.width}
111→              height={viewport.height}
112→              fill={viewport.source.kind === '3d_preview' ? '#f8fafc' : SHEET_COLORS.paper}
113→              stroke={isSelected ? '#0f8f74' : SHEET_COLORS.border}
114→              strokeWidth={isSelected ? 0.8 : 0.45}
115→            />
116→            <rect
117→              x={viewport.contentRect.x}
118→              y={viewport.contentRect.y}
119→              width={viewport.contentRect.width}
120→              height={viewport.contentRect.height}
121→              fill="none"
122→              stroke={SHEET_COLORS.divider}
123→              strokeWidth={0.18}
124→              pointerEvents="none"
125→            />
126→            {viewport.source.kind === 'empty' ? (
127→              <EmptyViewportMessage viewport={viewport} message={viewport.source.message} />
128→            ) : (
129→              <svg
130→                x={viewport.clipRect.x}
131→                y={viewport.clipRect.y}
132→                width={viewport.clipRect.width}
133→                height={viewport.clipRect.height}
134→                viewBox={`0 0 ${viewport.clipRect.width} ${viewport.clipRect.height}`}
135→                overflow="hidden"
136→                pointerEvents="none"
137→              >
138→                <g
139→                  transform={`translate(${viewport.contentTransform.translateX}, ${viewport.contentTransform.translateY}) scale(${viewport.contentTransform.scale})`}
140→                  pointerEvents="none"
141→                >
142→                  <SheetViewportContent source={viewport.source} />
143→                </g>
144→              </svg>
145→            )}
146→            {isSelected && Object.values(getViewportHandleRects(viewport, HANDLE_SIZE)).map((handleRect) => (
147→              <rect
148→                key={`${viewport.id}-${handleRect.x}-${handleRect.y}`}
149→                x={handleRect.x}
150→                y={handleRect.y}
151→                width={handleRect.width}
152→                height={handleRect.height}
153→                fill="#ffffff"
154→                stroke="#0f8f74"
155→                strokeWidth={0.5}
156→              />
157→            ))}
158→            {isSelected && (() => {
159→              const rh = getViewportRotationHandle(viewport, HANDLE_SIZE);
160→              return (
161→                <>
162→                  <line
163→                    x1={rh.stemX}
164→                    y1={rh.stemY1}
165→                    x2={rh.stemX}
166→                    y2={rh.stemY2}
167→                    stroke="#0f8f74"
168→                    strokeWidth={0.4}
169→                  />
170→                  <circle
171→                    cx={rh.cx}
172→                    cy={rh.cy}
173→                    r={rh.radius}
174→                    fill="#ffffff"
175→                    stroke="#0f8f74"
176→                    strokeWidth={0.5}
177→                    style={{ cursor: 'grab' }}
178→                  />
179→                </>
180→              );
181→            })()}
182→          </g>
183→        );
184→      })}
185→    </g>
186→  );
