 78→function formatCaptionSecondary(viewport, source, sheet) {
 79→  const scaleLabel = resolveViewportScaleLabel(viewport, source, sheet);
 80→  const reference = resolveViewportReferenceNote(viewport, source);
 81→  return `${reference}  |  SCALE ${scaleLabel}`;
