231→function rectFromArea(area) {
232→  return {
233→    x: area.x,
234→    y: area.y,
235→    width: area.width,
236→    height: area.height,
237→  };
238→}
239→
240→function partitionByRole(entries) {
241→  const primary = [];
242→  const secondary = [];
243→  const supplemental = [];
244→
245→  entries.forEach((entry, index) => {
246→    const role = entry.viewport.role
247→      || (entry.source.kind === '3d_preview' ? 'supplemental' : (index === 0 ? 'primary' : 'secondary'));
248→
249→    if (role === 'supplemental' || entry.source.kind === '3d_preview') {
250→      supplemental.push(entry);
251→    } else if (role === 'primary') {
252→      primary.push(entry);
253→    } else {
254→      secondary.push(entry);
255→    }
256→  });
257→
258→  return { primary, secondary, supplemental };
259→}
260→
261→function stackAreas(area, count) {
262→  if (count <= 0) return [];
263→  if (count === 1) return [rectFromArea(area)];
264→  if (count >= 4) {
265→    const columns = 2;
266→    const rows = Math.ceil(count / columns);
267→    const cellWidth = (area.width - SHEET_TOKENS.viewportGutter) / columns;
268→    const cellHeight = (area.height - SHEET_TOKENS.viewportGutter * (rows - 1)) / rows;
269→    return Array.from({ length: count }, (_, index) => {
270→      const column = index % columns;
271→      const row = Math.floor(index / columns);
272→      return {
273→        x: area.x + column * (cellWidth + SHEET_TOKENS.viewportGutter),
274→        y: area.y + row * (cellHeight + SHEET_TOKENS.viewportGutter),
275→        width: cellWidth,
276→        height: cellHeight,
277→      };
278→    });
279→  }
280→
281→  const height = (area.height - SHEET_TOKENS.viewportGutter * (count - 1)) / count;
282→  return Array.from({ length: count }, (_, index) => ({
283→    x: area.x,
284→    y: area.y + index * (height + SHEET_TOKENS.viewportGutter),
285→    width: area.width,
286→    height,
287→  }));
288→}
289→
290→function layoutAutoViewports(entries, area) {
291→  if (!entries.length) return new Map();
292→
293→  const result = new Map();
294→  const roles = partitionByRole(entries);
295→  const primaryEntry = roles.primary[0] || roles.secondary[0] || roles.supplemental[0];
296→  const secondaryEntries = [
297→    ...roles.primary.slice(primaryEntry && roles.primary[0] === primaryEntry ? 1 : 0),
298→    ...roles.secondary.filter((entry) => entry !== primaryEntry),
299→    ...roles.supplemental.filter((entry) => entry !== primaryEntry),
300→  ];
301→
302→  if (!primaryEntry) return result;
303→
304→  const onlySupplemental = primaryEntry.source.kind === '3d_preview'
305→    && secondaryEntries.every((entry) => entry.source.kind === '3d_preview');
306→
307→  if (!secondaryEntries.length) {
308→    result.set(primaryEntry.viewport.id, rectFromArea(area));
309→    return result;
310→  }
311→
312→  if (onlySupplemental) {
313→    const areas = stackAreas(area, 1 + secondaryEntries.length);
314→    [primaryEntry, ...secondaryEntries].forEach((entry, index) => {
315→      result.set(entry.viewport.id, areas[index]);
316→    });
317→    return result;
318→  }
319→
320→  const primaryWidthRatio = secondaryEntries.length >= 3 ? 0.58 : 0.64;
321→  const primaryArea = {
322→    x: area.x,
323→    y: area.y,
324→    width: area.width * primaryWidthRatio - SHEET_TOKENS.viewportGutter / 2,
325→    height: area.height,
326→  };
327→  const sideArea = {
328→    x: primaryArea.x + primaryArea.width + SHEET_TOKENS.viewportGutter,
329→    y: area.y,
330→    width: area.width - primaryArea.width - SHEET_TOKENS.viewportGutter,
331→    height: area.height,
332→  };
333→
334→  result.set(primaryEntry.viewport.id, rectFromArea(primaryArea));
335→  stackAreas(sideArea, secondaryEntries.length).forEach((rect, index) => {
336→    result.set(secondaryEntries[index].viewport.id, rect);
337→  });
338→
339→  return result;
340→}
