451→export function getDefaultViewportRect(sheet, source, scale = 100, options = {}) {
452→  const paper = getPaperPreset(sheet.paperSize);
453→  const zones = buildSheetZones(paper);
454→  const bounds = source.bounds || { minX: 0, maxX: 1000, minY: 0, maxY: 1000 };
455→  const sourceWidth = Math.max(1000, bounds.maxX - bounds.minX);
456→  const sourceHeight = Math.max(1000, bounds.maxY - bounds.minY);
457→  const role = options.role || (source.kind === '3d_preview' ? 'supplemental' : 'primary');
458→  const baseScale = source.kind === '3d_preview' ? 1 : Math.max(1, scale);
459→  const width = clamp(
460→    source.kind === '3d_preview'
461→      ? zones.contentArea.width * 0.72
462→      : (sourceWidth / baseScale) + SHEET_TOKENS.viewportPadding * 2,
463→    role === 'primary' ? 120 : 84,
464→    role === 'primary' ? zones.contentArea.width * 0.72 : zones.contentArea.width * 0.44
465→  );
466→  const height = clamp(
467→    source.kind === '3d_preview'
468→      ? zones.contentArea.height * 0.54
469→      : (sourceHeight / baseScale) + SHEET_TOKENS.viewportPadding * 2,
470→    role === 'primary' ? 96 : 72,
471→    role === 'primary' ? zones.contentArea.height * 0.78 : zones.contentArea.height * 0.42
472→  );
473→
474→  return snapRectToGrid({
475→    x: zones.contentArea.x + SHEET_TOKENS.viewportGutter,
476→    y: zones.contentArea.y + SHEET_TOKENS.viewportGutter,
477→    width,
478→    height,
479→  });
480→}
