 53→    const ctx = {
 54→      dispatch, editorDispatch,
 55→      getFloor: (...args) => getFloorRef.current(...args),
 56→      activeFloorId, viewport, snapEnabled,
 57→    };
 58→
 59→    switch (activeTool) {
 60→      case TOOLS.DIMENSION:
 61→        return createDimensionPlaceHandler(ctx);
 62→      case TOOLS.WALL:
 63→        return createWallDrawHandler(ctx);
 64→      case TOOLS.BEAM:
 65→        return createBeamPlaceHandler(ctx);
 66→      case TOOLS.STAIR:
 67→        return createStairPlaceHandler(ctx);
 68→      case TOOLS.SECTION:
 69→        return createSectionPlaceHandler(ctx);
 70→      case TOOLS.SLAB:
 71→        return createSlabPlaceHandler(ctx);
 72→      case TOOLS.ROOM:
 73→        return createRoomPlaceHandler(ctx);
 74→      case TOOLS.SELECT:
 75→        return createSelectHandler(ctx);
 76→      case TOOLS.DOOR:
 77→        return createDoorPlaceHandler(ctx);
 78→      case TOOLS.WINDOW:
 79→        return createWindowPlaceHandler(ctx);
 80→      case TOOLS.COLUMN:
 81→        return createColumnPlaceHandler(ctx);
 82→      case TOOLS.LANDING:
 83→        return createLandingPlaceHandler(ctx);
 84→      case TOOLS.FIXTURE:
