 28→            {...SECONDARY} {...NSS} fill="none" />
 29→          {/* 4 burners */}
 30→          {[[bx1, by1], [bx2, by1], [bx1, by2], [bx2, by2]].map(([cx, cy], i) => (
 31→            <g key={i}>
 32→              <circle cx={cx} cy={cy} r={bOuter} fill="none" {...PRIMARY} {...NSS} />
 33→              <circle cx={cx} cy={cy} r={bInner} fill="none" {...SECONDARY} {...NSS} />
 34→            </g>
